import React, { useState, useEffect } from 'react';
import { LoadScript, GoogleMap, Marker } from '@react-google-maps/api';
import WebSocketService from '../services/WebSocketService';
import mapStyles from '../components/mapStyles';
import Charts from '../components/Charts';
import StatCard from '../components/StatCard';
import api from '../services/api';

const DashboardHome = () => {
  const [vehicles, setVehicles] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [mapError, setMapError] = useState(null);
  const [dataError, setDataError] = useState(null);

  const mapContainerStyle = {
    height: '400px',
    width: '100%',
  };

  const center = {
    lat: 37.7749, // San Francisco
    lng: -122.4194,
  };

  useEffect(() => {
    // Fetch initial data
    const fetchInitialData = async () => {
      try {
        const vehiclesData = await api.getVehicles();
        const alertsData = await api.getAlerts();
        setVehicles(Array.isArray(vehiclesData) ? vehiclesData : []);
        setAlerts(Array.isArray(alertsData) ? alertsData.slice(0, 5) : []);
      } catch (err) {
        console.error('Error fetching initial data:', err);
        setDataError('Failed to load vehicles or alerts');
      }
    };
    fetchInitialData();

    // WebSocket subscriptions
    try {
      WebSocketService.connect();
      WebSocketService.subscribe('/topic/vehicles', (data) => {
        setVehicles(Array.isArray(data) ? data : []);
      });
      WebSocketService.subscribe('/topic/alerts', (data) => {
        setAlerts(Array.isArray(data) ? data.slice(0, 5) : []);
      });
    } catch (err) {
      console.error('WebSocket error:', err);
      setDataError('Failed to connect to real-time updates');
    }

    return () => {
      WebSocketService.disconnect();
    };
  }, []);

  // Stat card data
  const activeVehicles = vehicles?.filter((v) => v.status === 'ACTIVE').length || 0;
  const totalAlerts = alerts?.length || 0;
  const maintenanceVehicles = vehicles?.filter((v) => v.status === 'MAINTENANCE').length || 0;

  return (
    <div className="container p-6">
      <h1 className="text-2xl g-brand mb-6">Fleet Dashboard</h1>

      {/* Error Display */}
      {dataError && <div className="g-error mb-6">{dataError}</div>}

      {/* Stat Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
        <StatCard title="Active Vehicles" value={activeVehicles} icon="truck" color="bg-blue-500" />
        <StatCard title="Recent Alerts" value={totalAlerts} icon="bell" color="bg-red-500" />
        <StatCard title="Vehicles in Maintenance" value={maintenanceVehicles} icon="wrench" color="bg-yellow-500" />
      </div>

      {/* Google Map */}
      <div className="stat-card mb-6">
        <h2 className="text-lg font-semibold mb-4 no-underline">Vehicle Locations</h2>
        {mapError ? (
          <div className="g-error">Failed to load map: {mapError}</div>
        ) : (
          <LoadScript
            googleMapsApiKey={process.env.REACT_APP_GOOGLE_MAPS_API_KEY}
            onError={(err) => {
              console.error('Google Maps error:', err);
              setMapError('Invalid API key or network issue');
            }}
            onLoad={() => console.log('Google Maps loaded')}
          >
            <GoogleMap
              mapContainerStyle={mapContainerStyle}
              center={center}
              zoom={12}
              options={{ styles: mapStyles.light }}
            >
              {vehicles?.map((vehicle) => (
                <Marker
                  key={vehicle.id}
                  position={{ lat: vehicle.lat, lng: vehicle.lng }}
                  label={vehicle.status?.[0] || ''}
                  icon={{
                    url: `/icons/vehicle-${vehicle.status?.toLowerCase() || 'unknown'}.svg`,
                    scaledSize: new window.google.maps.Size(32, 32),
                  }}
                />
              ))}
            </GoogleMap>
          </LoadScript>
        )}
      </div>

      {/* Charts */}
      <div className="mb-6">
        <Charts />
      </div>

      {/* Recent Alerts */}
      <div className="stat-card">
        <h2 className="text-lg font-semibold mb-4 no-underline">Recent Alerts</h2>
        {alerts?.length === 0 ? (
          <p className="text-gray-600">No recent alerts</p>
        ) : (
          <ul className="list-disc pl-5">
            {alerts?.map((alert, index) => (
              <li key={index} className="text-gray-700 mb-2" spellCheck={false}>
                {alert.type} (Vehicle {alert.vehicleId}) - {new Date(alert.timestamp).toLocaleTimeString()}
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
};

export default DashboardHome;
